select public.seed_structured_concept('expansion-batch-06','contrast-aki','Medical-Surgical','contrast-associated kidney injury risk','a client with chronic kidney disease needs iodinated contrast','Review renal function and nephrotoxins and use prescribed hydration and lowest appropriate contrast exposure','Follow instructions about fluids and medicines and report reduced urine or swelling','Creatinine rises sharply with oliguria after contrast','Give additional nephrotoxic medicine','Ignore metformin instructions','Restrict all fluids without indication','Reduction of Risk Potential');
select public.seed_structured_concept('expansion-batch-06','spine-surgery','Medical-Surgical','neurologic compromise after spinal surgery','a postoperative client needs frequent motor and sensory checks','Maintain alignment and assess strength, sensation, pain, bladder function, and wound drainage','Use logrolling and report new weakness, numbness, saddle anesthesia, or loss of bladder control','New bilateral leg weakness with urinary retention','Twist at the waist during transfer','Place pillows causing spinal rotation','Delay reporting new paralysis','Reduction of Risk Potential');
select public.seed_structured_concept('expansion-batch-06','mastectomy-arm','Medical-Surgical','arm care after axillary lymph-node surgery','a client is at risk for lymphedema and shoulder limitation','Protect the affected side, promote prescribed range of motion, and monitor swelling and infection','Avoid constriction and skin injury and report persistent swelling, redness, or heaviness','Rapid arm swelling with redness and fever','Use tight jewelry on the affected arm','Allow routine blood pressures on that side when alternatives exist','Avoid all shoulder movement indefinitely','Reduction of Risk Potential');
select public.seed_structured_concept('expansion-batch-06','peritoneal-dialysis','Medical-Surgical','peritoneal dialysis peritonitis','cloudy effluent with abdominal pain and fever','Save the effluent sample, notify the dialysis team, and administer prescribed antimicrobial therapy','Use meticulous aseptic connection technique and report cloudy drainage immediately','Cloudy outflow with rebound tenderness and hypotension','Warm dialysate in a microwave','Continue exchanges without reporting cloudy fluid','Touch sterile connectors with bare hands','Reduction of Risk Potential');
select public.seed_structured_concept('expansion-batch-06','chest-tube-air-leak','Medical-Surgical','a new chest-tube air leak','continuous bubbling appears in the water-seal chamber','Assess the client and system and locate loose connections according to policy','Keep the system upright and below the chest and report new continuous bubbling or dyspnea','Sudden distress with no tidaling and absent breath sounds','Strip tubing forcefully','Clamp routinely during transport','Ignore continuous bubbling','Reduction of Risk Potential');

-- Physiological Adaptation
select public.seed_structured_concept('expansion-batch-06','stemi','Emergency and Critical Care','acute ST-elevation myocardial infarction','crushing chest pressure, diaphoresis, ST elevation, and nausea','Activate reperfusion protocol, obtain rapid ECG-based care, and give prescribed antiplatelet and supportive therapy','Call emergency services for persistent chest pressure and do not drive yourself','Recurrent pain with ventricular tachycardia and hypotension','Delay care to finish household tasks','Walk to relieve chest pressure','Take an interacting erectile-dysfunction drug with nitrate','Physiological Adaptation');
select public.seed_structured_concept('expansion-batch-06','acute-heart-failure','Medical-Surgical','acute decompensated heart failure','orthopnea, crackles, edema, hypoxemia, and jugular venous distention','Sit upright, support oxygenation, give prescribed diuretic and vasodilator therapy, and monitor response','Track daily weight and report rapid gain, swelling, or increasing breathlessness','Pink frothy sputum with severe hypoxemia','Give a large unmonitored fluid bolus','Place the client flat','Encourage high-sodium food','Physiological Adaptation');
select public.seed_structured_concept('expansion-batch-06','acute-kidney-injury','Medical-Surgical','acute kidney injury','rising creatinine, oliguria, edema, and electrolyte disturbance','Identify the cause, stop nephrotoxins, monitor fluid and electrolytes, and treat urgent complications','Avoid unapproved NSAIDs and report reduced urine, swelling, weakness, or breathlessness','Potassium 6.7 mEq/L with widening QRS complexes','Give potassium supplements','Force excessive fluid despite pulmonary edema','Continue nephrotoxic contrast without review','Physiological Adaptation');
select public.seed_structured_concept('expansion-batch-06','variceal-bleed','Medical-Surgical','bleeding esophageal varices','cirrhosis with massive hematemesis, hypotension, and altered consciousness','Protect the airway, establish large-bore access, and prepare prescribed vasoactive and endoscopic therapy','Avoid alcohol and NSAIDs and seek emergency care for vomiting blood or black stool','Ongoing hematemesis with inability to protect the airway','Insert a nasogastric tube without an order','Offer food and oral fluids','Delay blood preparation','Physiological Adaptation');
select public.seed_structured_concept('expansion-batch-06','major-burn','Emergency and Critical Care','a major thermal burn','large partial- and full-thickness burns with facial soot and hoarseness','Secure the airway early, begin calculated fluid resuscitation, prevent hypothermia, and assess associated trauma','Cool minor burns with running water but seek emergency care for large, deep, facial, airway, electrical, or chemical burns','Increasing hoarseness and stridor after an enclosed-space fire','Apply ice directly to extensive burns','Break intact blisters','Delay airway assessment until edema is obvious','Physiological Adaptation');
select public.seed_structured_concept('expansion-batch-06','bacterial-meningitis-adult','Medical-Surgical','acute bacterial meningitis','fever, severe headache, neck stiffness, photophobia, and altered consciousness','Initiate droplet precautions and give prescribed antibiotics promptly after appropriate cultures','Close contacts may need prophylaxis and urgent evaluation is required for fever with stiff neck or confusion','Purpuric rash with shock and declining consciousness','Delay antibiotics for final culture results','Place in a bright noisy room','Use standard precautions alone initially','Physiological Adaptation');

